use std::cmp::Ordering;
use std::collections::{BinaryHeap, HashMap};

#[derive(Copy, Clone, Eq, PartialEq)]
struct Node {
    position: (usize, usize),
    f_score: usize,
    g_score: usize,
}

impl Ord for Node {
    fn cmp(&self, other: &Self) -> Ordering {
        other.f_score.cmp(&self.f_score)
    }
}

impl PartialOrd for Node {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

fn manhattan_distance(a: (usize, usize), b: (usize, usize)) -> usize {
    ((a.0 as isize - b.0 as isize).abs() + (a.1 as isize - b.1 as isize).abs()) as usize
}

fn find_path_in_maze(maze: Vec<Vec<i32>>, start: (usize, usize), end: (usize, usize)) -> Option<Vec<(usize, usize)>> {
    let rows = maze.len();
    if rows == 0 {
        return None;
    }
    let cols = maze[0].len();

    let mut open_set = BinaryHeap::new();
    let mut came_from: HashMap<(usize, usize), (usize, usize)> = HashMap::new();
    let mut g_score: HashMap<(usize, usize), usize> = HashMap::new();

    g_score.insert(start, 0);
    open_set.push(Node {
        position: start,
        f_score: manhattan_distance(start, end),
        g_score: 0,
    });

    while let Some(current) = open_set.pop() {
        let (x, y) = current.position;

        if current.position == end {
            // Reconstruct path
            let mut path = vec![end];
            let mut current_pos = end;

            while current_pos != start {
                current_pos = came_from[&current_pos];
                path.push(current_pos);
            }

            path.reverse();
            return Some(path);
        }

        let directions = [(0, 1), (1, 0), (0, -1), (-1, 0)];

        for (dx, dy) in directions.iter() {
            let nx = x as isize + dx;
            let ny = y as isize + dy;

            if nx < 0 || nx >= rows as isize || ny < 0 || ny >= cols as isize {
                continue;
            }

            let neighbor = (nx as usize, ny as usize);

            if maze[neighbor.0][neighbor.1] == 1 {
                continue;  // Wall
            }

            let tentative_g_score = current.g_score + 1;

            if !g_score.contains_key(&neighbor) || tentative_g_score < g_score[&neighbor] {
                came_from.insert(neighbor, current.position);
                g_score.insert(neighbor, tentative_g_score);

                let f_score = tentative_g_score + manhattan_distance(neighbor, end);
                open_set.push(Node {
                    position: neighbor,
                    f_score,
                    g_score: tentative_g_score,
                });
            }
        }
    }

    None  // No path found
}
