private int checkProperties(Node node, int blackCount, int blackHeight) {
    if (node == null) {
        // Reached a leaf node (null), which is black
        if (blackHeight == -1) {
            // First leaf node encountered, set the black height
            return blackCount;
        }
        // Check if this path has same black height as other paths
        return (blackCount == blackHeight) ? blackHeight : -1;
    }

    // Check if a red node has red children
    if (isRed(node) && (isRed(node.left) || isRed(node.right))) {
        return -1;
    }

    // Increment black count if current node is black
    if (!isRed(node)) {
        blackCount++;
    }

    // Recursively check left and right subtrees
    int leftBlackHeight = checkProperties(node.left, blackCount, blackHeight);
    if (leftBlackHeight == -1) return -1;

    blackHeight = leftBlackHeight;  // Update black height

    return checkProperties(node.right, blackCount, blackHeight);
}

private boolean isRed(Node node) {
