def min_operations(n):
    if n <= 1:
        return 0

    # Find prime factors
    prime_factors = set()
    i = 2
    temp = n
    while i * i <= temp:
        if temp % i == 0:
            prime_factors.add(i)
            while temp % i == 0:
                temp //= i
        i += 1
    if temp > 1:
        prime_factors.add(temp)

    # Dynamic programming approach
    dp = [float('inf')] * (n + 1)
    dp[1] = 0

    for i in range(2, n + 1):
        # Subtract 1
        dp[i] = min(dp[i], dp[i - 1] + 1)

        # Divide by prime factors
        for factor in prime_factors:
            if i % factor == 0:
                dp[i] = min(dp[i], dp[i // factor] + 1)

    return dp[n]
