import java.nio.charset.StandardCharsets;
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.util.BitSet;

public class EmailBloomFilter {
    private BitSet bitSet;
    private int size;
    private int hashFunctionCount;

    public EmailBloomFilter(int size, int hashFunctionCount) {
        this.size = size;
        this.hashFunctionCount = hashFunctionCount;
        this.bitSet = new BitSet(size);
    }

    public void add(String email) {
        for (int i = 0; i < hashFunctionCount; i++) {
            int hash = getHash(email, i);
            bitSet.set(hash);
        }
    }

    public boolean checkEmailMembership(String email) {
        for (int i = 0; i < hashFunctionCount; i++) {
            int hash = getHash(email, i);
            if (!bitSet.get(hash)) {
                return false;
            }
        }
        return true;
    }

    private int getHash(String email, int index) {
        try {
            MessageDigest digest = MessageDigest.getInstance("SHA-256");
            String input = email + index;
            byte[] hash = digest.digest(input.getBytes(StandardCharsets.UTF_8));

            // Convert to positive integer and take modulo size
            int result = 0;
            for (int i = 0; i < 4; i++) {
                result = (result << 8) | (hash[i] & 0xff);
            }
            return Math.abs(result % size);
        } catch (NoSuchAlgorithmException e) {
            throw new RuntimeException("SHA-256 not available", e);
        }
    }
}
