function findCentroids(dataPoints, k) {
  if (!dataPoints.length || k <= 0) {
    return [];
  }

  // Initialize centroids randomly from data points
  let centroids = [];
  const usedIndices = new Set();

  while (centroids.length < k && centroids.length < dataPoints.length) {
    const randomIndex = Math.floor(Math.random() * dataPoints.length);
    if (!usedIndices.has(randomIndex)) {
      usedIndices.add(randomIndex);
      centroids.push({x: dataPoints[randomIndex].x, y: dataPoints[randomIndex].y});
    }
  }

  const MAX_ITERATIONS = 100;
  let iterations = 0;
  let centroidsChanged = true;

  while (centroidsChanged && iterations < MAX_ITERATIONS) {
    // Assign each point to the nearest centroid
    const clusters = Array(k).fill().map(() => []);

    for (const point of dataPoints) {
      let minDistance = Infinity;
      let closestCentroidIndex = 0;

      for (let i = 0; i < centroids.length; i++) {
        const distance = Math.sqrt(
          Math.pow(point.x - centroids[i].x, 2) + 
          Math.pow(point.y - centroids[i].y, 2)
        );

        if (distance < minDistance) {
          minDistance = distance;
          closestCentroidIndex = i;
        }
      }

      clusters[closestCentroidIndex].push(point);
    }

    // Update centroids
    centroidsChanged = false;

    for (let i = 0; i < k; i++) {
      if (clusters[i].length === 0) continue;

      const sumX = clusters[i].reduce((sum, point) => sum + point.x, 0);
      const sumY = clusters[i].reduce((sum, point) => sum + point.y, 0);
      const newX = sumX / clusters[i].length;
      const newY = sumY / clusters[i].length;

      if (Math.abs(newX - centroids[i].x) > 0.001 || Math.abs(newY - centroids[i].y) > 0.001) {
        centroidsChanged = true;
        centroids[i] = {x: newX, y: newY};
      }
    }

    iterations++;
  }

  return centroids;
}
