fn find_all_scc(graph: &Vec<Vec<usize>>) -> Vec<Vec<usize>> {
    let n = graph.len();
    let mut visited = vec![false; n];
    let mut stack = Vec::new();

    // First DFS to fill the stack
    for i in 0..n {
        if !visited[i] {
            fill_order(i, graph, &mut visited, &mut stack);
        }
    }

    // Create transpose of the graph
    let mut transpose = vec![Vec::new(); n];
    for i in 0..n {
        for &j in &graph[i] {
            transpose[j].push(i);
        }
    }

    // Reset visited array
    visited = vec![false; n];

    // Process vertices in order defined by the stack
    let mut scc_result = Vec::new();
    while let Some(v) = stack.pop() {
        if !visited[v] {
            let mut component = Vec::new();
            dfs_collect(v, &transpose, &mut visited, &mut component);
            scc_result.push(component);
        }
    }

    scc_result
}

fn fill_order(v: usize, graph: &Vec<Vec<usize>>, visited: &mut Vec<bool>, stack: &mut Vec<usize>) {
    visited[v] = true;

    for &i in &graph[v] {
        if !visited[i] {
            fill_order(i, graph, visited, stack);
        }
    }

    stack.push(v);
}

fn dfs_collect(v: usize, graph: &Vec<Vec<usize>>, visited: &mut Vec<bool>, component: &mut Vec<usize>) {
    visited[v] = true;
    component.push(v);

    for &i in &graph[v] {
        if !visited[i] {
            dfs_collect(i, graph, visited, component);
        }
    }
}
