    int end;
} Interval;

typedef struct Node {
    Interval interval;
    int max_end;
    struct Node* left;
    struct Node* right;
} Node;

Node* create_node(Interval interval) {
    Node* node = (Node*)malloc(sizeof(Node));
    node->interval = interval;
    node->max_end = interval.end;
    node->left = NULL;
    node->right = NULL;
    return node;
}

int max(int a, int b) {
    return (a > b) ? a : b;
}

int do_overlap(Interval a, Interval b) {
    return (a.start <= b.end && b.start <= a.end);
}

Interval merge_intervals(Interval a, Interval b) {
    Interval result;
    result.start = min(a.start, b.start);
    result.end = max(a.end, b.end);
    return result;
}

void update_max_end(Node* root) {
    if (root == NULL) return;

    root->max_end = root->interval.end;
    if (root->left != NULL)
        root->max_end = max(root->max_end, root->left->max_end);
    if (root->right != NULL)
        root->max_end = max(root->max_end, root->right->max_end);
}

Node* interval_insert(Node* root, Interval interval) {
    if (root == NULL)
        return create_node(interval);

    if (do_overlap(root->interval, interval)) {
        root->interval = merge_intervals(root->interval, interval);
        update_max_end(root);
        return root;
    }

    if (interval.start < root->interval.start)
        root->left = interval_insert(root->left, interval);
    else
        root->right = interval_insert(root->right, interval);

    if (root->max_end < interval.end)
        root->max_end = interval.end;

    return root;
}
