public static String findLongestRepeatedSubstring(String text) {
    int n = text.length();

    // Create suffix array
    Integer[] sa = new Integer[n];
    for (int i = 0; i < n; i++) {
        sa[i] = i;
    }

    // Sort suffixes
    Arrays.sort(sa, (a, b) -> text.substring(a).compareTo(text.substring(b)));

    // LCP array
    int[] lcp = new int[n];
    int maxLen = 0;
    int maxIndex = 0;

    for (int i = 1; i < n; i++) {
        int len = 0;
        int a = sa[i - 1];
        int b = sa[i];

        while (a + len < n && b + len < n && text.charAt(a + len) == text.charAt(b + len)) {
            len++;
        }

        lcp[i] = len;

        if (len > maxLen) {
            maxLen = len;
            maxIndex = i;
        }
    }

    if (maxLen == 0) {
        return "";
    }

    return text.substring(sa[maxIndex], sa[maxIndex] + maxLen);
}
