struct SuffixTreeNode {
    std::unordered_map<char, SuffixTreeNode*> children;
    int start;
    int* end;
    int suffixIndex;

    SuffixTreeNode(int start, int* end) {
        this->start = start;
        this->end = end;
        this->suffixIndex = -1;
    }
};

class SuffixTree {
private:
    std::string text;
    SuffixTreeNode* root;
    int size;
    int* leafEnd;
    SuffixTreeNode* lastNewNode;
    SuffixTreeNode* activeNode;
    int activeEdge;
    int activeLength;
    int remainingSuffixCount;
    int leafIndex;

    SuffixTreeNode* newNode(int start, int* end) {
        return new SuffixTreeNode(start, end);
    }

    int edgeLength(SuffixTreeNode* n) {
        return *(n->end) - n->start + 1;
    }

    bool walkDown(SuffixTreeNode* currNode) {
        if (activeLength >= edgeLength(currNode)) {
            activeEdge += edgeLength(currNode);
            activeLength -= edgeLength(currNode);
            activeNode = currNode;
            return true;
        }
        return false;
    }

    void extendSuffixTree(int pos) {
        leafEnd = new int(pos);
        remainingSuffixCount++;
        lastNewNode = nullptr;

        while (remainingSuffixCount > 0) {
            if (activeLength == 0) {
                activeEdge = pos;
            }

            if (activeNode->children.find(text[activeEdge]) == activeNode->children.end()) {
                activeNode->children[text[activeEdge]] = newNode(pos, leafEnd);
                if (lastNewNode != nullptr) {
                    lastNewNode->suffixIndex = leafIndex;
                    lastNewNode = nullptr;
                }
            } else {
                SuffixTreeNode* next = activeNode->children[text[activeEdge]];
                if (walkDown(next)) {
                    continue;
                }

                if (text[next->start + activeLength] == text[pos]) {
                    if (lastNewNode != nullptr) {
                        lastNewNode->suffixIndex = leafIndex;
                        lastNewNode = nullptr;
                    }
                    activeLength++;
                    break;
                }

                int* splitEnd = new int(next->start + activeLength - 1);
                SuffixTreeNode* split = newNode(next->start, splitEnd);
                activeNode->children[text[activeEdge]] = split;

                split->children[text[pos]] = newNode(pos, leafEnd);
                next->start += activeLength;
                split->children[text[next->start]] = next;

                if (lastNewNode != nullptr) {
                    lastNewNode->suffixIndex = leafIndex;
                }

                lastNewNode = split;
            }

            remainingSuffixCount--;
            if (activeNode == root && activeLength > 0) {
                activeLength--;
                activeEdge = pos - remainingSuffixCount + 1;
            } else if (activeNode != root) {
                activeNode = root;
            }
        }
    }

    void buildSuffixTree() {
        size = text.length();
        leafEnd = nullptr;
        root = newNode(-1, new int(-1));
        activeNode = root;
        activeEdge = -1;
        activeLength = 0;
        remainingSuffixCount = 0;
        leafIndex = 0;

        for (int i = 0; i < size; i++) {
            extendSuffixTree(i);
        }
    }

    void dfs(SuffixTreeNode* node, int depth, std::vector<int>& maxDepth, int& maxIndex) {
        if (node == nullptr) return;

        bool isLeaf = true;
        for (auto& child : node->children) {
            isLeaf = false;
            int currentDepth = depth + edgeLength(child.second);
            dfs(child.second, currentDepth, maxDepth, maxIndex);
        }

        if (!isLeaf && node != root) {
            if (depth > maxDepth[0]) {
                maxDepth[0] = depth;
                maxIndex = node->start;
                maxDepth[1] = node->start;
                maxDepth[2] = depth;
            }
        }
    }

    std::string findLongestRepeatedSubstring() {
        std::vector<int> maxDepth(3, 0);
        int maxIndex = -1;
        dfs(root, 0, maxDepth, maxIndex);

        if (maxDepth[0] == 0) return "";

        return text.substr(maxDepth[1] - maxDepth[2] + 1, maxDepth[0]);
    }

public:
    SuffixTree(const std::string& s) : text(s + "$") {
        buildSuffixTree();
    }

    ~SuffixTree() {
        // Clean up memory (would need a recursive deletion function)
    }

    std::string findLongest() {
        return findLongestRepeatedSubstring();
    }
};

std::string longest_repeated_substring(const std::string& s) {
    if (s.length() <= 1) return "";

    SuffixTree tree(s);
    return tree.findLongest();
}
