int* compute_lps(const char* pattern, int m) {
    int* lps = (int*)malloc(m * sizeof(int));
    if (!lps) return NULL;

    int len = 0;
    lps[0] = 0;

    for (int i = 1; i < m; ) {
        if (pattern[i] == pattern[len]) {
            len++;
            lps[i] = len;
            i++;
        } else {
            if (len != 0) {
                len = lps[len - 1];
            } else {
                lps[i] = 0;
                i++;
            }
        }
    }

    return lps;
}

int substring_search(const char* text, const char* pattern) {
    if (!text || !pattern) return -1;

    int n = strlen(text);
    int m = strlen(pattern);

    if (m == 0) return 0;
    if (n < m) return -1;

    int* lps = compute_lps(pattern, m);
    if (!lps) return -1;

    int i = 0; // for text
    int j = 0; // for pattern

    while (i < n) {
        if (pattern[j] == text[i]) {
            i++;
            j++;
        }

        if (j == m) {
            free(lps);
            return i - j; // Found the pattern
        } else if (i < n && pattern[j] != text[i]) {
            if (j != 0) {
                j = lps[j - 1];
            } else {
                i++;
            }
        }
    }

    free(lps);
    return -1; // Pattern not found
}
