public class HuffmanCompression {

    private static class Node implements Comparable<Node> {
        char ch;
        int freq;
        Node left, right;

        Node(char ch, int freq) {
            this.ch = ch;
            this.freq = freq;
            left = right = null;
        }

        Node(char ch, int freq, Node left, Node right) {
            this.ch = ch;
            this.freq = freq;
            this.left = left;
            this.right = right;
        }

        @Override
        public int compareTo(Node other) {
            return this.freq - other.freq;
        }
    }

    public static String compressData(String input) {
        if (input == null || input.isEmpty()) {
            return "";
        }

        // Count frequency of each character
        Map<Character, Integer> freqMap = new HashMap<>();
        for (char c : input.toCharArray()) {
            freqMap.put(c, freqMap.getOrDefault(c, 0) + 1);
        }

        // Build Huffman Tree
        PriorityQueue<Node> minHeap = new PriorityQueue<>();
        for (Map.Entry<Character, Integer> entry : freqMap.entrySet()) {
            minHeap.offer(new Node(entry.getKey(), entry.getValue()));
        }

        // Create Huffman tree by combining nodes
        while (minHeap.size() > 1) {
            Node left = minHeap.poll();
            Node right = minHeap.poll();
            minHeap.offer(new Node('\0', left.freq + right.freq, left, right));
        }

        Node root = minHeap.poll();

        // Generate codes for each character
        Map<Character, String> huffmanCodes = new HashMap<>();
        generateCodes(root, "", huffmanCodes);

        // Build compressed string
        StringBuilder compressed = new StringBuilder();
        for (char c : input.toCharArray()) {
            compressed.append(huffmanCodes.get(c));
        }

        // Store tree structure and compressed data
        StringBuilder result = new StringBuilder();

        // Store character codes for decompression
        for (Map.Entry<Character, String> entry : huffmanCodes.entrySet()) {
            result.append(entry.getKey())
                  .append(':')
                  .append(entry.getValue())
                  .append(';');
        }

        // Separator between codes and compressed data
        result.append('|').append(compressed);

        return result.toString();
    }

    private static void generateCodes(Node root, String code, Map<Character, String> huffmanCodes) {
        if (root == null) {
            return;
        }

        // Found a leaf node with a character
        if (root.left == null && root.right == null) {
            huffmanCodes.put(root.ch, code.length() > 0 ? code : "0");
        }

        generateCodes(root.left, code + "0", huffmanCodes);
        generateCodes(root.right, code + "1", huffmanCodes);
    }
}
