use std::fmt::Write;

fn calculate_sha1_digest(input: &str) -> String {
    // Initial hash values (h0 through h4)
    let mut h0: u32 = 0x67452301;
    let mut h1: u32 = 0xEFCDAB89;
    let mut h2: u32 = 0x98BADCFE;
    let mut h3: u32 = 0x10325476;
    let mut h4: u32 = 0xC3D2E1F0;

    // Pre-processing
    let message_bytes = input.as_bytes();
    let original_bit_len = (message_bytes.len() * 8) as u64;

    // Process the message in 512-bit chunks
    let mut i = 0;
    let mut ml = message_bytes.len();
    let mut chunk = [0u8; 64]; // 512 bits = 64 bytes

    while i < ml || (i % 64) != 56 {
        if i < ml {
            chunk[i % 64] = message_bytes[i];
        } else if i == ml {
            chunk[i % 64] = 0x80; // Append a single '1' bit
        } else {
            chunk[i % 64] = 0; // Padding with zeros
        }

        if (i % 64) == 63 {
            process_chunk(&mut h0, &mut h1, &mut h2, &mut h3, &mut h4, &chunk);
        }

        i += 1;
    }

    // Append the original length as a 64-bit big-endian integer
    for j in 0..8 {
        chunk[56 + j] = ((original_bit_len >> (56 - j * 8)) & 0xff) as u8;
    }

    process_chunk(&mut h0, &mut h1, &mut h2, &mut h3, &mut h4, &chunk);

    // Produce the final hash value
    let mut result = String::with_capacity(40);
    write!(result, "{:08x}{:08x}{:08x}{:08x}{:08x}", h0, h1, h2, h3, h4).unwrap();

    result
}

fn process_chunk(h0: &mut u32, h1: &mut u32, h2: &mut u32, h3: &mut u32, h4: &mut u32, chunk: &[u8; 64]) {
    let mut w = [0u32; 80];

    // Break chunk into 16 32-bit big-endian words
    for i in 0..16 {
        w[i] = ((chunk[i * 4] as u32) << 24)
             | ((chunk[i * 4 + 1] as u32) << 16)
             | ((chunk[i * 4 + 2] as u32) << 8)
             | (chunk[i * 4 + 3] as u32);
    }

    // Extend the 16 32-bit words into 80 32-bit words
    for i in 16..80 {
        w[i] = left_rotate(w[i-3] ^ w[i-8] ^ w[i-14] ^ w[i-16], 1);
    }

    // Initialize hash values for this chunk
    let mut a = *h0;
    let mut b = *h1;
    let mut c = *h2;
    let mut d = *h3;
    let mut e = *h4;

    // Main loop
    for i in 0..80 {
        let (f, k) = match i {
            0..=19 => ((b & c) | ((!b) & d), 0x5A827999),
            20..=39 => (b ^ c ^ d, 0x6ED9EBA1),
            40..=59 => ((b & c) | (b & d) | (c & d), 0x8F1BBCDC),
            _ => (b ^ c ^ d, 0xCA62C1D6),
        };

        let temp = left_rotate(a, 5).wrapping_add(f)
                                    .wrapping_add(e)
                                    .wrapping_add(k)
                                    .wrapping_add(w[i]);

        e = d;
        d = c;
        c = left_rotate(b, 30);
        b = a;
        a = temp;
    }

    // Add this chunk's hash to the result
    *h0 = h0.wrapping_add(a);
    *h1 = h1.wrapping_add(b);
    *h2 = h2.wrapping_add(c);
    *h3 = h3.wrapping_add(d);
    *h4 = h4.wrapping_add(e);
}

fn left_rotate(value: u32, shift: u32) -> u32 {
    (value << shift) | (value >> (32 - shift))
}
