pub struct Node<T> {
    val: T,
    next: Option<Box<Node<T>>>,
}

pub fn merge_sort_list<T: Ord + Clone>(head: Option<Box<Node<T>>>) -> Option<Box<Node<T>>> {
    if head.is_none() || head.as_ref().unwrap().next.is_none() {
        return head;
    }

    let mut slow = head.clone();
    let mut fast = head.clone();
    let mut prev = None;

    // Find the middle of the list
    while fast.is_some() && fast.as_ref().unwrap().next.is_some() {
        fast = fast.unwrap().next.unwrap().next;
        prev = slow;
        slow = slow.unwrap().next;
    }

    // Split the list into two halves
    prev.unwrap().next = None;

    // Recursively sort both halves
    let left = merge_sort_list(head);
    let right = merge_sort_list(slow);

    // Merge the sorted halves
    merge(left, right)
}

fn merge<T: Ord + Clone>(left: Option<Box<Node<T>>>, right: Option<Box<Node<T>>>) -> Option<Box<Node<T>>> {
    match (left, right) {
        (None, right) => right,
        (left, None) => left,
        (Some(mut left_node), Some(mut right_node)) => {
            if left_node.val <= right_node.val {
                left_node.next = merge(left_node.next, Some(right_node));
                Some(left_node)
            } else {
                right_node.next = merge(Some(left_node), right_node.next);
                Some(right_node)
            }
        }
    }
}
