public boolean isBalancedAvlTree(AvlTreeNode root) {
    if (root == null) {
        return true;
    }

    int minDepth = Integer.MAX_VALUE;
    int maxDepth = Integer.MIN_VALUE;

    // Use DFS to find min and max leaf depths
    findMinMaxLeafDepth(root, 0, minDepth, maxDepth);

    // The tree is balanced if the difference between min and max leaf depths is at most 1
    return maxDepth - minDepth <= 1;
}

private void findMinMaxLeafDepth(AvlTreeNode node, int currentDepth, int minDepth, int maxDepth) {
    if (node == null) {
        return;
    }

    // If it's a leaf node, update min and max depths
    if (node.left == null && node.right == null) {
        minDepth = Math.min(minDepth, currentDepth);
        maxDepth = Math.max(maxDepth, currentDepth);
        return;
    }

    // Continue DFS on both children
    findMinMaxLeafDepth(node.left, currentDepth + 1, minDepth, maxDepth);
    findMinMaxLeafDepth(node.right, currentDepth + 1, minDepth, maxDepth);
}
