int find_max_flow(int **graph, int source, int sink, int vertices) {
    int **residual_graph = (int **)malloc(vertices * sizeof(int *));
    for (int i = 0; i < vertices; i++) {
        residual_graph[i] = (int *)malloc(vertices * sizeof(int));
        for (int j = 0; j < vertices; j++) {
            residual_graph[i][j] = graph[i][j];
        }
    }

    int *parent = (int *)malloc(vertices * sizeof(int));
    int max_flow = 0;

    // Augment the flow while there is a path from source to sink
    while (bfs(residual_graph, source, sink, parent, vertices)) {
        // Find the maximum flow through the path found
        int path_flow = INT_MAX;
        for (int v = sink; v != source; v = parent[v]) {
            int u = parent[v];
            path_flow = (path_flow < residual_graph[u][v]) ? path_flow : residual_graph[u][v];
        }

        // Update residual capacities of the edges and reverse edges
        for (int v = sink; v != source; v = parent[v]) {
            int u = parent[v];
            residual_graph[u][v] -= path_flow;
            residual_graph[v][u] += path_flow;
        }

        max_flow += path_flow;
    }

    // Free allocated memory
    for (int i = 0; i < vertices; i++) {
        free(residual_graph[i]);
    }
    free(residual_graph);
    free(parent);

    return max_flow;
}

// BFS to find an augmenting path
int bfs(int **residual_graph, int source, int sink, int *parent, int vertices) {
    int *visited = (int *)calloc(vertices, sizeof(int));

    // Create a queue, enqueue source
    int *queue = (int *)malloc(vertices * sizeof(int));
    int front = 0, rear = 0;
    queue[rear++] = source;
    visited[source] = 1;
    parent[source] = -1;

    // Standard BFS loop
    while (front < rear) {
        int u = queue[front++];

        for (int v = 0; v < vertices; v++) {
            if (visited[v] == 0 && residual_graph[u][v] > 0) {
                queue[rear++] = v;
                parent[v] = u;
                visited[v] = 1;
            }
        }
    }

    // Free memory and return if sink was reached
    free(queue);
    int reached = visited[sink];
    free(visited);
    return reached;
}
