fn is_prime_miller_rabin(num: u64) -> bool {
    if num <= 1 {
        return false;
    }
    if num <= 3 {
        return true;
    }
    if num % 2 == 0 {
        return false;
    }

    let witnesses = if num < 2_047 {
        &[2]
    } else if num < 1_373_653 {
        &[2, 3]
    } else if num < 9_080_191 {
        &[31, 73]
    } else if num < 25_326_001 {
        &[2, 3, 5]
    } else if num < 3_215_031_751 {
        &[2, 3, 5, 7]
    } else {
        &[2, 3, 5, 7, 11, 13, 17]
    };

    let r = (num - 1).trailing_zeros();
    let d = (num - 1) >> r;

    'witness: for &a in witnesses {
        if a >= num {
            continue;
        }
        let mut x = mod_pow(a, d, num);
        if x == 1 || x == num - 1 {
            continue 'witness;
        }

        for _ in 0..r - 1 {
            x = mod_mul(x, x, num);
            if x == num - 1 {
                continue 'witness;
            }
        }
        return false;
    }
    true
}

fn mod_pow(mut base: u64, mut exp: u64, modulus: u64) -> u64 {
    if modulus == 1 {
        return 0;
    }
    let mut result = 1;
    base %= modulus;
    while exp > 0 {
        if exp & 1 == 1 {
            result = mod_mul(result, base, modulus);
        }
        exp >>= 1;
        base = mod_mul(base, base, modulus);
    }
    result
}

fn mod_mul(a: u64, b: u64, modulus: u64) -> u64 {
    // Use wrapping multiplication to avoid overflow
    let mut result = 0;
    let mut a = a % modulus;
    let mut b = b % modulus;

    while b > 0 {
        if b & 1 == 1 {
            result = (result + a) % modulus;
        }
        a = (a << 1) % modulus;
        b >>= 1;
    }
    result
}
